fn update_metric_text(name: &str, value: &str) {
    honeycomb::canvas_app::METRIC_TEXT_IDS.with(|m| {
        let ids: Vec<(String, u32)> = m.borrow().clone();
        // Try wasm_api::TREE first (handler may have just rebuilt here)
        honeycomb::wasm_api::TREE.with(|t| {
            let mut tree = t.borrow_mut();
            for (n, id) in &ids {
                if n == name {
                    if let Some(el) = tree.get_mut(*id) { el.text = Some(value.to_string()); }
                }
            }
        });
        // Also try AppState.tree (for filter/sort that don't rebuild)
        honeycomb::canvas_app::STATE.with(|s| {
            if let Some(ref mut app) = *s.borrow_mut() {
                for (n, id) in &ids {
                    if n == name {
                        if let Some(el) = app.tree.get_mut(*id) { el.text = Some(value.to_string()); }
                    }
                }
            }
        });
    });
}

fn filter_by(attr: &str, value: &str) {
    honeycomb::canvas_app::wasm_filter_by_attr(
        attr.as_ptr(), attr.len() as u32, value.as_ptr(), value.len() as u32);
}
fn to_ms_string(start: f64, end: f64) -> String {
    let us = ((end - start) * 1000.0) as u64;
    if us >= 1000 { format!("{}.{:02}ms", us / 1000, (us % 1000) / 10) }
    else { format!("0.{:03}ms", us) }
}

