fn treebench_on_search() {
    let _op_t0 = perf_now();
    TREEBENCH_STATE.with(|s| {
        let mut state = s.borrow_mut();
        state.query = honeycomb::canvas_app::last_input_text();
        if (state.capacity == 0) {
            state.status = "not connected — click Connect first".to_string();
            return;
        }
        let ql = state.query.to_lowercase().clone();
        let mut toks = vec![];
        let mut rest = format!("{}", ql);
        while (rest.len() as i32 > 0) {
            let sp = rest.find(" ").map(|i| i as i32).unwrap_or(-1);
            if (sp < 0) {
                toks.push(format!("{}", rest));
                rest = format!("");
            } else {
                if (sp > 0) {
                    toks.push({ let _s = &rest; let _start = (0) as usize; let _end = (sp) as usize; _s.get(_start.._end.min(_s.len())).unwrap_or("").to_string() });
                }
                rest = { let _s = &rest; let _start = ((sp + 1)) as usize; let _end = (rest.len() as i32) as usize; _s.get(_start.._end.min(_s.len())).unwrap_or("").to_string() };
            }
        }
        let t0 = perf_now();
        if (toks.len() as i32 == 0) {
            state.visible = vec![];
            let mut stack = vec![0];
            while (stack.len() as i32 > 0) {
                let idx = stack.pop().unwrap();
                state.visible.push(idx);
                if state.expanded[idx as usize] {
                    if state.loaded[idx as usize] {
                        let cc = state.children_count[idx as usize];
                        let fc = ((idx * state.branching) + 1);
                        let mut c = (cc - 1);
                        while (c >= 0) {
                            stack.push((fc + c));
                            c = (c - 1);
                        }
                    }
                }
            }
            state.filter_label = "full structure".to_string();
        } else {
            state.visible = vec![];
            let mut i = 0;
            while (i < state.capacity) {
                if (state.names[i as usize].len() as i32 > 0) {
                    let mut hit = 0;
                    let mut t = 0;
                    while (t < toks.len() as i32) {
                        if state.hay[i as usize].contains(&toks[t as usize]) {
                            hit = (hit + 1);
                        }
                        t = (t + 1);
                    }
                    if (hit == toks.len() as i32) {
                        state.visible.push(i);
                    }
                }
                i = (i + 1);
            }
            state.filter_label = format!("search \"{}\"", state.query);
        }
        let scan_ms = (perf_now() - t0);
        state.scroll_row = 0;
        if (state.scroll_row < 0) {
            state.scroll_row = 0;
        }
        let max_scroll = (state.visible.len() as i32 - state.viewport_rows);
        if (max_scroll < 0) {
            if (state.scroll_row > 0) {
                state.scroll_row = 0;
            }
        } else {
            if (state.scroll_row > max_scroll) {
                state.scroll_row = max_scroll;
            }
        }
        state.window_ids = vec![];
        state.window_depths = vec![];
        let total_visible = state.visible.len() as i32;
        let mut r = state.scroll_row;
        let end = (r + state.viewport_rows);
        while (r < end) {
            if (r >= 0) {
                if (r < total_visible) {
                    let id = state.visible[r as usize];
                    let mut dd2 = id;
                    let mut depth2 = 0;
                    while (dd2 > 0) {
                        dd2 = ((dd2 - 1) / state.branching);
                        depth2 = (depth2 + 1);
                    }
                    state.window_ids.push(id);
                    state.window_depths.push(depth2);
                }
            }
            r = (r + 1);
        }
        if (state.loaded_count < 70000) {
            state.status = format!("search \"{}\": {} matches in {:.2}ms — searched {} loaded nodes only (Import full BOM to search all 71,284)", state.query, state.visible.len() as i32, scan_ms, state.loaded_count);
        } else {
            state.status = format!("search \"{}\": scanned {} nodes → {} matches in {:.2}ms", state.query, state.loaded_count, state.visible.len() as i32, scan_ms);
        }
    });
    // Re-render after state change
    let _t_rebuild = perf_now();
    // Clear stale registrations before tree rebuild
    honeycomb::canvas_app::clear_registrations();
    with_tree(|tree| {
        let root = tree.root_id();
        tree.remove_children_recursive(root);
    });
    treebench_mount();
    let _t_mounted = perf_now();
    render();
    let _t_laid = perf_now();
    {
        let msg = format!("REBUILD mount={:.2}ms layout={:.2}ms", _t_mounted - _t_rebuild, _t_laid - _t_mounted);
        unsafe { console_log(msg.as_ptr(), msg.len() as u32); }
    }
    let _op_elapsed = to_ms_string(_op_t0, perf_now());
    TREEBENCH_STATE.with(|s| s.borrow_mut().last_op_ms = _op_elapsed.clone());
    update_metric_text("last_op_ms", &_op_elapsed);
}

